<?php
$pageTitle='Warehouse Dispatch';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('warehouse_dispatch');
$pdo=getDB();
$warehouses=$pdo->query('SELECT id,warehouse_name FROM '.table('warehouses').' ORDER BY warehouse_name')->fetchAll();$packs=$pdo->query('SELECT * FROM '.table('packing_slips').' ORDER BY created_at DESC LIMIT 100')->fetchAll();$products=$pdo->query('SELECT id,sku,name FROM '.table('products').' ORDER BY name LIMIT 500')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)$_POST['action'];if($action==='dispatch'){$num=nextScopedDocumentNumber($pdo,'warehouse_dispatch',setting('warehouse_dispatch_prefix','DISP-WH'),operationalScope($pdo));$user=currentUser();$pdo->prepare('INSERT INTO '.table('warehouse_dispatches').' (dispatch_number,packing_slip_id,warehouse_id,carrier,tracking_number,status,dispatched_by,dispatched_at,notes) VALUES (?,?,?,?,?,"dispatched",?,NOW(),?)')->execute([$num,(int)$_POST['packing_slip_id']?:null,(int)$_POST['warehouse_id'],trim((string)$_POST['carrier']),trim((string)$_POST['tracking_number']),(int)($user['id']??0)?:null,trim((string)$_POST['notes'])]);flash('success','Warehouse dispatch created.');}elseif($action==='item'){$pdo->prepare('INSERT INTO '.table('warehouse_dispatch_items').' (warehouse_dispatch_id,product_id,dispatch_qty) VALUES (?,?,?)')->execute([(int)$_POST['dispatch_id'],(int)$_POST['product_id'],max(0,(float)$_POST['dispatch_qty'])]);flash('success','Dispatch item added.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'warehouse-dispatch']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/warehouse-dispatch.php');}
$dispatches=$pdo->query('SELECT d.*,w.warehouse_name,p.packing_number FROM '.table('warehouse_dispatches').' d LEFT JOIN '.table('warehouses').' w ON w.id=d.warehouse_id LEFT JOIN '.table('packing_slips').' p ON p.id=d.packing_slip_id ORDER BY d.created_at DESC LIMIT 100')->fetchAll();
$items=$pdo->query('SELECT i.*,d.dispatch_number,p.sku,p.name FROM '.table('warehouse_dispatch_items').' i LEFT JOIN '.table('warehouse_dispatches').' d ON d.id=i.warehouse_dispatch_id LEFT JOIN '.table('products').' p ON p.id=i.product_id ORDER BY i.created_at DESC LIMIT 120')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Carrier Handover</div><h2 class="h4 mb-1">Warehouse Dispatch</h2><p class="text-secondary mb-0">Create dispatch records, carrier tracking, and dispatch item history.</p></div></div><div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="dispatch"><h2 class="h5 mb-3">Create Dispatch</h2><select class="form-select mb-2" name="packing_slip_id"><option value="0">No packing slip</option><?php foreach($packs as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['packing_number']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?php echo (int)$w['id']; ?>"><?php echo esc($w['warehouse_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="carrier" placeholder="Carrier"><input class="form-control mb-2" name="tracking_number" placeholder="Tracking number"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Dispatch</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="item"><h2 class="h5 mb-3">Add Dispatch Item</h2><select class="form-select mb-2" name="dispatch_id"><?php foreach($dispatches as $d): ?><option value="<?php echo (int)$d['id']; ?>"><?php echo esc($d['dispatch_number']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><input class="form-control mb-3" type="number" step="0.0001" name="dispatch_qty" value="1"><button class="btn btn-outline-primary w-100">Add Item</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Dispatches</h2><table class="table"><thead><tr><th>Dispatch</th><th>Packing</th><th>Warehouse</th><th>Carrier</th><th>Status</th></tr></thead><tbody><?php foreach($dispatches as $d): ?><tr><td><strong><?php echo esc($d['dispatch_number']); ?></strong><div class="small text-secondary"><?php echo esc($d['tracking_number']); ?></div></td><td><?php echo esc($d['packing_number']); ?></td><td><?php echo esc($d['warehouse_name']); ?></td><td><?php echo esc($d['carrier']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($d['status'])); ?>"><?php echo esc($d['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Dispatch Items</h2><table class="table"><thead><tr><th>Dispatch</th><th>Product</th><th>Qty</th></tr></thead><tbody><?php foreach($items as $i): ?><tr><td><?php echo esc($i['dispatch_number']); ?></td><td><?php echo esc($i['sku'].' · '.$i['name']); ?></td><td><?php echo number_format((float)$i['dispatch_qty'],4); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>